import React, { useState, useEffect } from 'react';
import { Loader, Button } from '@salutejs/plasma-web';
export function App() {
    const [loading, setLoading] = useState(false);
    const handleShowLoader = () => {
        setLoading(true);
    };
    useEffect(() => {
        if (loading) {
            const timer = setTimeout(() => {
                setLoading(false);
            }, 5000);
            return () => clearTimeout(timer);
        }
    }, [loading]);
    return (
        <div style={{ position: 'relative', height: '200px' }}>
            <Button onClick={handleShowLoader}>Показать загрузку</Button>
            {loading && (
                <Loader
                    type="spinner"
                    hasOverlay
                    withBlur
                />
            )}
        </div>
    );
}

